// Data Normalization
// Normalize fields and batch into groups of 3 for Gemini API calls

const items = $input.all();
const batches = [];
const BATCH_SIZE = 3;

// Normalize each item first
const normalizedItems = items.map((item, index) => {
  const json = item.json;
  const reviewId = json.review_id ||
    `csv_${Date.now()}_${index}_${Math.random().toString(36).substr(2, 6)}`;

  return {
    source: 'csv',
    product_id: json.product_id || null,
    product_name: (json.product_name || 'Unknown').trim(),
    review_id: reviewId,
    reviewer_name: json.reviewer_name || null,
    rating: parseFloat(json.rating) || 3,
    review_title: (json.review_title || '').trim(),
    review_text: (json.review_text || '').trim(),
    review_date: json.review_date || new Date().toISOString().split('T')[0],
    country: json.country || 'Unknown',
    language: json.language || 'en'
  };
});

// Batch into groups for Gemini API calls
for (let i = 0; i < normalizedItems.length; i += BATCH_SIZE) {
  const batch = normalizedItems.slice(i, i + BATCH_SIZE);
  batches.push({
    json: {
      batch_index: Math.floor(i / BATCH_SIZE),
      reviews: batch,
      prompt: `You are an analytics classifier for product reviews.\n\nFor each review below, return a JSON array where each element matches:\n{\n  "review_id": string,\n  "sentiment": "positive" | "neutral" | "negative",\n  "sentiment_score": number between -1.0 and 1.0,\n  "topics": string[] (1-6 lowercase topics),\n  "urgency": "low" | "med" | "high",\n  "summary": string,\n  "key_phrases": string[]\n}\n\nTopics can include: battery, pricing, delivery, support, ui, performance, durability, setup, compatibility, sound, screen, design, other.\nIf safety hazard or severe defect, urgency must be "high".\n\nReviews:\n${JSON.stringify(batch, null, 2)}\n\nReturn ONLY a valid JSON array. No explanation.`
    }
  });
}

return batches;

// LLM Classification
// Parse Gemini response and merge with original batch data

const items = $input.all();
const output = [];

for (const item of items) {
  const geminiResponse = item.json;

  // Extract text from Gemini response structure
  let responseText = '';
  try {
    responseText = geminiResponse.candidates[0].content.parts[0].text;
  } catch (e) {
    console.error('Failed to extract Gemini response text:', e.message);
    continue;
  }

  // Parse the JSON array returned by Gemini
  let classifications = [];
  try {
    // Remove markdown code blocks if present
    const cleaned = responseText
      .replace(/```json\n?/g, '')
      .replace(/```\n?/g, '')
      .trim();
    classifications = JSON.parse(cleaned);
  } catch (e) {
    console.error('Failed to parse Gemini JSON:', e.message);
    continue;
  }

  // Find matching original review data from the Data Normalization node
  // We retrieve it from the paired input item's reviews array
  const originalReviews = item.json._inputData?.reviews || [];

  // Emit one output item per classified review
  for (const cls of classifications) {
    // Find the original review by review_id
    const original = originalReviews.find(r => r.review_id === cls.review_id) || {};

    output.push({
      json: {
        source: original.source || 'csv',
        product_id: original.product_id || null,
        product_name: original.product_name || null,
        review_id: cls.review_id || original.review_id,
        reviewer_name: original.reviewer_name || null,
        rating: original.rating || null,
        review_title: original.review_title || null,
        review_text: original.review_text || null,
        review_date: original.review_date || null,
        country: original.country || null,
        language: original.language || 'en',
        sentiment: cls.sentiment,
        sentiment_score: cls.sentiment_score,
        topics: cls.topics,
        urgency: cls.urgency,
        summary: cls.summary,
        key_phrases: cls.key_phrases,
        ai_model: 'gemini-1.5-flash',
        ai_raw_json: geminiResponse
      }
    });
  }
}

return output;
